def assess(record: dict) -> str:
    required = {"case_id", "dependency_layer_reused", "digest_stable", "lock_copied_before_source", "source_change_rebuilds"}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    ok = not (not record["dependency_layer_reused"] and record["source_change_rebuilds"] > 3)
